.mean()\n    diff = ema12 - ema26\n    return diff\n\ndf['macd_diff'] = df.groupby('code')['close'].transform(calculate_macd)\n\n# Calculate 60-day MA\ndf['ma_60'] = df.groupby('code')['close'].transform(lambda x: x.rolling(60).mean())\n\n# Check if 60-day MA is monotonically increasing over last 10 days\ndef check_ma_increasing(ma_series):\n    last_10 = ma_series.tail(10)\n    if len(last_10) < 10:\n        return False\n    return all(last_10.iloc[i] < last_10.iloc[i+1] for i in range(len(last_10)-1))\n\n# Get latest data for each stock\nlatest = df.groupby('code').tail(1).copy()\n\n# For MA slope check, need last 10 days of MA_60\nma_slope_check = []\nfor code in latest['code']:\n    stock_data = df[df['code'] == code].tail(10)\n    if len(stock_data) >= 10:\n        ma_60_vals = stock_data['ma_60'].values\n        is_increasing = all(ma_60_vals[i] < ma_60_vals[i+1] for i in range(len(ma_60_vals)-1))\n        ma_slope = (ma_60_vals[-1] - ma_60_vals[0]) / ma_60_vals[0] if ma_60_vals[0] != 0 else 0\n    else:\n        is_increasing = False\n        ma_slope = 0\n    ma_slope_check.append({'code': code, 'ma_increasing': is_increasing, 'ma_slope': ma_slope})\n\nma_df = pd.DataFrame(ma_slope_check)\nlatest = latest.merge(ma_df, on='code', how='left')\n\n# Apply filters\nfiltered = latest[\n    (latest['momentum_20d'] > 15) &\n    (latest['reversal_5d'] < -3) &\n    (latest['rsi_14'] >= 30) &\n    (latest['rsi_14'] <= 50) &\n    (latest['macd_diff'] > 0) &\n    (latest['ma_increasing'] == True)\n].copy()\n\n# Sort by 20-day momentum descending\nfiltered = filtered.sort_values('momentum_20d', ascending=False)\n\n# Take top 10\ntop_10 = filtered.head(10)\n\n# Prepare output\noutput_path = Path('/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_29_momentum_reversal_combo/revised/claudecode/momentum_reversal.txt')\n\nwith open(output_path, 'w') as f:\n    f.write('股票代码,20日动量(%),5日反转(%),RSI,MACD_DIFF,60日均线斜率\\n')\