{"type":"assistant","message":{"content":[{"id":"tooluse_fkejGJpIuRkqC1YJ7Jd1vu","input":{"file_path":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_29_momentum_reversal_combo/revised/claudecode/momentum_analysis.py","content":"import pandas as pd\nimport numpy as np\nimport akshare as ak\nfrom pathlib import Path\nfrom datetime import datetime, timedelta\n\n# Get A-share stock list\nprint(\"Fetching stock list...\")\nstock_list = ak.stock_zh_a_spot_em()\nstock_codes = stock_list['代码'].tolist()[:500]  # Limit to first 500 for performance\n\n# Date range\nend_date = '20241108'\nstart_date = '20240801'  # Need enough history for 60-day MA\n\nresults = []\n\nprint(f\"Analyzing {len(stock_codes)} stocks...\")\nfor i, code in enumerate(stock_codes):\n    if i % 50 == 0:\n        print(f\"Progress: {i}/{len(stock_codes)}\")\n\n    try:\n        # Fetch historical data\n        df = ak.stock_zh_a_hist(symbol=code, period='daily',\n                                start_date=start_date, end_date=end_date, adjust='qfq')\n\n        if len(df) < 70:  # Need at least 70 days for calculations\n            continue\n\n        df = df.sort_values('日期')\n        df['close'] = df['收盘']\n\n        # Calculate 20-day momentum (cumulative return)\n        if len(df) >= 20:\n            momentum_20d = (df['close'].iloc[-1] / df['close'].iloc[-21] - 1) * 100\n        else:\n            continue\n\n        # Calculate 5-day reversal (cumulative return)\n        if len(df) >= 5:\n            reversal_5d = (df['close'].iloc[-1] / df['close'].iloc[-6] - 1) * 100\n        else:\n            continue\n\n        # Calculate RSI (14-day)\n        delta = df['close'].diff()\n        gain = delta.where(delta > 0, 0).rolling(window=14).mean()\n        loss = -delta.where(delta < 0, 0).rolling(window=14).mean()\n        rs = gain / loss\n        rsi = 100 - (100 / (1 + rs))\n        rsi_14 = rsi.iloc[-1]\n\n        # Calculate MACD DIFF\n        ema12 = df['close'].ewm(span=12, adjust=False).mean()\n        ema26 = df['close'].ewm(span=26, adjust=False).mean()\n        macd_diff = (ema12 - ema26).iloc[-1]\n\n        # Calculate 60-day MA\n        ma_60 = df['close'].rolling(window=60).mean()\n\n        # Check if 60-day MA is monotonically increasing over last 10 days\n        if len(ma_60) >= 10:\n            last_10_ma = ma_60.iloc[-10:].values\n            if np.isnan(last_10_ma).any():\n                continue\n            ma_increasing = all(last_10_ma[i] < last_10_ma[i+1] for i in range(len(last_10_ma)-1))\n            ma_slope = (last_10_ma[-1] - last_10_ma[0]) / last_10_ma[0]\n        else:\n            continue\n\n        # Apply filters\n        if (momentum_20d > 15 and\n            reversal_5d < -3 and\n            30 <= rsi_14 <= 50 and\n            macd_diff > 0 and\n            ma_increasing):\n\n            results.append({\n                'code': code,\n                'momentum_20d': momentum_20d,\n                'reversal_5d': reversal_5d,\n                'rsi_14': rsi_14,\n                'macd_diff': macd_diff,\n                'ma_slope': ma_slope\n            })\n\n    except Exception as e:\n        continue\n\nprint(f\"\\nFound {len(results)} stocks matching all criteria\")\n\n# Sort by 20-day momentum descending\nresults_df = pd.DataFrame(results)\nif len(results_df) > 0:\n    results_df = results_df.sort_values('momentum_20d', ascending=False)\n    top_10 = results_df.head(10)\nelse:\n    top_10 = results_df\n\n# Write output\noutput_path = Path('/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_29_momentum_reversal_combo/revised/claudecode/momentum_reversal.txt')\n\nwith open(output_path, 'w', encoding='utf-8') as f:\n    f.write('股票代码,20日动量(%),5日反转(%),RSI,MACD_DIFF,60日均线斜率\\n')\n    if len(top_10) > 0:\n        for _, row in top_10.iterrows():\n            f.write(f\"{row['code']},{row['momentum_20d']:.2f},{row['reversal_5d']:.2f},\"\n                    f\"{row['rsi_14']:.2f},{row['macd_diff']:.4f},{row['ma_slope']:.4f}\\n\")\n    else:\n        f.write('# 无符合条件的股票\\n')\n\nprint(f\"Results written to {output_path}\")\nif len(top_10) > 0:\n    print(\"\\nTop 10 stocks:\")\n    print(top_10.to_string(index=False))\n"},"name":"Write","type":"tool_use"}],"id":"c5a0d294-dd60-44b1-b12a-c827b393dfa2","model":"claude-sonnet-4-6","role":"assistant","stop_reason":null,"stop_sequence":null,"type":"message","usage":{"cache_creation_input_tokens":944,"cache_read_input_tokens":0,"input_tokens":16298,"output_tokens":0},"context_management":null},"parent_tool_use_id":null,"session_id":"d0ea4afe-0fb0-4c50-93f8-b82b55e9dfce","uuid":"c314bce0-5e12-45c3-86dd-1e91370f0d54"}
